// เว็บแชทส่งข้อความรูปแบบ: "วิธีติดสติ๊กเกอร์ลูกค้า <ชื่อลูกค้าเต็ม>"
// ตัด prefix นี้ออก แล้วใช้ "ส่วนที่เหลือทั้งหมด" เป็นชื่อลูกค้า
// (ของเดิมใช้ regex ตัดแค่คำแรกหลัง "ลูกค้า" จึงดึงได้แค่คำกว้างๆ เช่น "Icing" แล้วค้นผิด record)
const body = $input.first().json.body || {};
const message = (body.message || '').toString().trim();

let customerName = message
  .replace(/^\s*วิธีติดสติ๊กเกอร์\s*ลูกค้า(?:ชื่อ)?\s*/, '')
  .trim();

if (!customerName) customerName = message;

return [{
  json: {
    message,
    customerName,
    sessionId: body.sessionId || null
  }
}];

// รวมทุก row จาก HTTP (รองรับทั้งคืนเป็น array ก้อนเดียว หรือแยกหลาย item)
const items = $input.all();
let rows = [];
for (const it of items) {
  if (Array.isArray(it.json)) rows = rows.concat(it.json);
  else if (it.json && it.json.customer_name) rows.push(it.json);
}

const customerName = ($('ดึงชื่อลูกค้าจากข้อความ').first().json.customerName || '').toString();

// normalize: ตัวเล็ก + ตัดช่องว่าง/อักขระพิเศษ เพื่อให้เทียบยืดหยุ่นขึ้น
function norm(s) {
  return (s || '').toString().toLowerCase().replace(/[\s*_\-./:(),]/g, '');
}
function bigrams(s) {
  const o = [];
  for (let i = 0; i < s.length - 1; i++) o.push(s.slice(i, i + 2));
  return o;
}
// Dice coefficient (0..1) วัดความคล้ายของสองสตริง
function dice(a, b) {
  if (!a || !b) return 0;
  if (a === b) return 1;
  const A = bigrams(a), B = bigrams(b);
  const m = {};
  for (const g of B) m[g] = (m[g] || 0) + 1;
  let x = 0;
  for (const g of A) if (m[g] > 0) { x++; m[g]--; }
  return (2 * x) / (A.length + B.length);
}

const q = norm(customerName);
let best = null, bestScore = 0;
for (const r of rows) {
  const name = norm(r.customer_name);
  let score = dice(q, name);
  // ถ้าพิมพ์บางส่วนที่อยู่ในชื่อ (เช่น "เวียงคำ") ให้ดันคะแนนขึ้น
  if (q.length >= 3 && (name.includes(q) || q.includes(name))) score = Math.max(score, 0.9);
  if (q === name) score = 1;
  if (score > bestScore) { bestScore = score; best = r; }
}

// ปรับค่าได้: สูง=แม่นแต่เข้มงวด, ต่ำ=ยืดหยุ่นแต่เสี่ยงผิด
const THRESHOLD = 0.55;

if (best && bestScore >= THRESHOLD) {
  const stepsText = `📦 วิธีติดสติ๊กเกอร์สำหรับลูกค้า ${best.customer_name}\n\n${best.steps}`;
  const imageUrls = Array.isArray(best.image_urls) ? best.image_urls : [];
  return [{ json: { messages: [
    { type: 'text', text: stepsText },
    ...imageUrls.map((url) => ({ type: 'image', url }))
  ] } }];
}

return [{ json: { messages: [
  { type: 'text', text: `ขออภัยค่ะ ยังไม่พบข้อมูลที่ตรงกับ "${customerName}"\nลองพิมพ์ชื่อลูกค้าให้ใกล้เคียงขึ้น หรือกดเลือกจากรายชื่อที่แนะนำนะคะ 🙏` }
] } }];

return [{
  json: {
    messages: [
      {
        type: 'text',
        text: 'รบกวนระบุชื่อลูกค้าด้วยนะคะ เช่น "วิธีติดสติ๊กเกอร์ลูกค้า Kaoshop" เพื่อให้ระบบค้นหาขั้นตอนการติดสติ๊กเกอร์ให้ถูกต้องค่ะ'
      }
    ]
  }
}];
